using System.Diagnostics;
using NUnit.Framework;

namespace Azure.AI.AgentServer.Core.Tests.Samples;

public class Sample3_FoundryTelemetry
{
    [Test]
    public void ConfigureFoundryTelemetryViaEnvironmentVariables()
    {
        #region Snippet:Core_Sample3_FoundryEnvVars
        // Set environment variables before starting the agent host to have every
        // OpenTelemetry span enriched with agent identity attributes.
        //
        // FOUNDRY_AGENT_NAME   =&gt; gen_ai.agent.name
        // FOUNDRY_AGENT_VERSION =&gt; gen_ai.agent.version
        // FOUNDRY_AGENT_NAME + &#34;:&#34; + FOUNDRY_AGENT_VERSION =&gt; gen_ai.agent.id  (computed)
        // FOUNDRY_PROJECT_ARM_ID =&gt; microsoft.foundry.project.id
        //
        // These are typically set by the Azure AI Foundry platform when the agent
        // server is running as a hosted agent. You can also set them locally for
        // local development and integration testing.
        //
        // var builder = AgentHost.CreateBuilder();
        // // ... register protocols ...
        // var app = builder.Build();
        // app.Run();
        //
        // Spans emitted by the host will include:
        //   gen_ai.agent.name    = &#34;my-agent&#34;
        //   gen_ai.agent.version = &#34;1.0.0&#34;
        //   gen_ai.agent.id      = &#34;my-agent:1.0.0&#34;
        //   microsoft.foundry.project.id = &#34;&#34;
        #endregion
    }
}
```

